use rusqlite::{params, Connection};
use crate::models::{Board, WorkItem};
pub fn list(conn: &Connection) -> Vec<Board> { let mut stmt = conn.prepare("SELECT code,name,summary,status,owner FROM boards ORDER BY name").unwrap(); stmt.query_map([], |row| Ok(Board { code: row.get(0)?, name: row.get(1)?, summary: row.get(2)?, status: row.get(3)?, owner: row.get(4)? })).unwrap().filter_map(Result::ok).collect() }
pub fn detail(conn: &Connection, code: &str) -> Option<(Board, Vec<WorkItem>)> { let board = conn.query_row("SELECT code,name,summary,status,owner FROM boards WHERE code=?1", [code], |row| Ok(Board { code: row.get(0)?, name: row.get(1)?, summary: row.get(2)?, status: row.get(3)?, owner: row.get(4)? })).ok()?; let mut stmt = conn.prepare("SELECT id,board_code,title,stage,priority,due_date FROM work_items WHERE board_code=?1 ORDER BY due_date").unwrap(); let items = stmt.query_map([code], |row| Ok(WorkItem { id: row.get(0)?, board_code: row.get(1)?, title: row.get(2)?, stage: row.get(3)?, priority: row.get(4)?, due_date: row.get(5)? })).unwrap().filter_map(Result::ok).collect(); Some((board, items)) }
pub fn create(conn: &Connection, code: &str, title: &str, stage: &str, priority: &str, due_date: &str, details: &str) { conn.execute("INSERT INTO work_items (board_code,title,stage,priority,due_date,details) VALUES (?1,?2,?3,?4,?5,?6)", params![code,title,stage,priority,due_date,details]).ok(); }
